// Solution
function formatListItems(inputString) {
  let listItems = inputString.match(/<li>(.*?)</li>/g);
  let formattedString = '';
  let isOrderedList = false;
  for (let i = 0; i < listItems.length; i++) {
    let item = listItems[i].replace(/<li>|</li>/g, '');
    if (!isOrderedList && listItems[i].includes('<ol>')) {
      formattedString += '<ol>';
      isOrderedList = true;
    } else if (isOrderedList && !listItems[i].includes('<ol>')) {
      formattedString += '</ol>';
      isOrderedList = false;
    }
    formattedString += '<li>' + item + '</li>';
  }
  if (isOrderedList) {
    formattedString += '</ol>';
  } else {
    formattedString += '</ul>';
  }
  return formattedString;
}
